files.content:
:host {
  display: block;
}
.agent-activity {
  margin: 0;
}
summary {
  align-items: center;
  color: var(--color-foreground-secondary);
  cursor: pointer;
  display: flex;
  gap: var(--dimension-space-050);
  list-style: none;
  padding: var(--dimension-space-025) 0;
}
summary::-webkit-details-marker {
  display: none;
}
details[open] summary ds-icon {
  transform: rotate(90deg);
}
ds-text.agent-activity__summary-label {
  min-width: 0;
}
ol {
  display: grid;
  gap: var(--dimension-space-075);
  list-style: none;
  margin: 0;
  padding: var(--dimension-space-100) 0 0 var(--dimension-space-200);
}
.agent-activity__item {
  align-items: start;
  display: grid;
  gap: var(--dimension-space-050);
  grid-template-columns: auto minmax(0, 1fr);
}
.agent-activity__marker {
  align-items: center;
  color: var(--color-foreground-faint-neutral);
  display: flex;
  padding-block-start: var(--dimension-space-025);
}
.agent-activity__item--active .agent-activity__marker {
  color: var(--color-foreground-faint-brand);
}
.agent-activity__item--error .agent-activity__marker {
  color: var(--color-foreground-bold-negative);
}
.agent-activity__item span:last-child {
  display: grid;
  gap: var(--dimension-space-025);
}
.agent-activity__pending-dot {
  width: var(--dimension-size-050);
  height: var(--dimension-size-050);
  border-radius: var(--dimension-radius-half);
  background: currentColor;
}
.agent-activity__state {
  position: absolute;
  width: var(--dimension-size-050);
  height: var(--dimension-size-050);
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
}

@media (prefers-reduced-motion: no-preference) {
  summary ds-icon {
    transition: transform var(--effect-motion-short-2);
  }
}

import { Component, Prop, State, Watch, h, Host } from '@stencil/core';
import type { AgentActivityItem } from '../conversation-types';

@Component({
  tag: 'ds-agent-activity',
  styleUrl: 'AgentActivity.css',
  scoped: true,
})
export class AgentActivity {
  @Prop() items: AgentActivityItem[] = [];
  @Prop() heading: string = 'Activity';
  @Prop() open: boolean = false;

  @State() private expanded: boolean = false;

  componentWillLoad() {
    this.expanded = this.open;
  }

  @Watch('open')
  handleOpenChange(open: boolean) {
    this.expanded = open;
  }

  private get currentItem(): AgentActivityItem | undefined {
    return (
      this.items.find(item => item.state === 'active') ??
      this.items.find(item => item.state === 'error') ??
      [...this.items].reverse().find(item => item.state === 'complete') ??
      this.items.find(item => item.state === 'pending')
    );
  }

  private handleToggle = (event: Event) => {
    this.expanded = (event.currentTarget as HTMLDetailsElement).open;
  };

  private stateLabel(item: AgentActivityItem): string {
    if (item.state === 'active') return 'In progress';
    if (item.state === 'complete') return 'Complete';
    if (item.state === 'error') return 'Error';
    return 'Pending';
  }

  render() {
    return (
      <Host>
        <details class="agent-activity" open={this.open} onToggle={this.handleToggle}>
          <summary>
            <ds-icon name="ChevronRight" size="xs" color="inherit" />
            <ds-text
              class="agent-activity__summary-label"
              variant="text-body-small"
              shimmer={!this.expanded && this.currentItem?.state === 'active'}
            >
              {this.expanded ? this.heading : this.currentItem?.label ?? this.heading}
            </ds-text>
          </summary>
          <ol>
            {this.items.map(item => (
              <li class={`agent-activity__item agent-activity__item--${item.state}`}>
                <span class="agent-activity__marker" aria-hidden="true">
                  {item.state === 'active' ? (
                    <ds-loader size="xs" color="inherit" />
                  ) : item.state === 'pending' ? (
                    <span class="agent-activity__pending-dot" />
                  ) : (
                    <ds-icon
                      name={item.state === 'error' ? 'ErrorTriangle' : 'Check'}
                      size="xs"
                      color="inherit"
                    />
                  )}
                </span>
                <span>
                  <ds-text variant="text-body-small" shimmer={item.state === 'active'}>
                    {item.label}
                  </ds-text>
                  {item.detail ? (
                    <ds-text variant="text-caption" color="secondary">
                      {item.detail}
                    </ds-text>
                  ) : null}
                  <span class="agent-activity__state">{this.stateLabel(item)}</span>
                </span>
              </li>
            ))}
          </ol>
        </details>
      </Host>
    );
  }
}
